import React, { useEffect } from "react";

export default function Toast({ message, type = "success", onClose }) {
  useEffect(() => {
    const t = setTimeout(onClose, 3500);
    return () => clearTimeout(t);
  }, [onClose]);

  const colors = {
    success: { bg: "#0d2e2e", border: "#00e5b0", text: "#00e5b0" },
    error: { bg: "#2e0d0d", border: "#ff4d6d", text: "#ff4d6d" },
    info: { bg: "#0d1e2e", border: "#00bcd4", text: "#00bcd4" },
  };
  const c = colors[type] || colors.info;

  return (
    <div
      style={{
        position: "fixed",
        bottom: 32,
        right: 32,
        zIndex: 9999,
        background: c.bg,
        border: `1px solid ${c.border}`,
        color: c.text,
        padding: "14px 22px",
        borderRadius: 10,
        fontFamily: "'DM Mono', monospace",
        fontSize: 14,
        maxWidth: 360,
        boxShadow: `0 0 30px ${c.border}40`,
        animation: "slideUp 0.3s ease",
        display: "flex",
        alignItems: "center",
        gap: 12,
      }}
      role="alert"
    >
      <span>{type === "success" ? "✓" : type === "error" ? "✗" : "ℹ"}</span>
      <span style={{ flex: 1 }}>{message}</span>
      <button
        onClick={onClose}
        style={{ background: "none", border: "none", color: c.text, cursor: "pointer", fontSize: 18 }}
        aria-label="Close"
      >
        ×
      </button>
    </div>
  );
}
